#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=1000005,inf=0x3f3f3f3f;
int n,m,dis[N],vis[N],ans[N];
struct node
{
	int u,w;
	bool operator<(const node other)  const
	{
		return w>other.w;
	}
};
priority_queue<node> pq;
struct Node
{
	int v,w;
};
vector<Node> g[N];
void dij()
{
	memset(dis,0x3f,sizeof(dis));
	while(!pq.empty()) pq.pop();
	dis[1]=0;
	ans[1]=1;
	pq.push(node{1,0});
	while(!pq.empty())
	{
		node t=pq.top();
		pq.pop();
		int u=t.u;
		ll w=t.w;
		if(vis[u]) continue;
		vis[u]=1;
		for(int i=0;i<g[u].size();i++)
		{
			Node tt=g[u][i];
			int v=tt.v,ww=tt.w;
			if(!vis[v]&&dis[u]+ww<dis[v])
			{
				dis[v]=dis[u]+ww;
				ans[v]=ans[u];
				pq.push(node{v,dis[v]});
			}
			else if(dis[u]+ww==dis[v])
			{
				ans[v]+=ans[u];
			}
		}
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		int x,y;
		cin>>x>>y;
		g[x].push_back(Node{y,1});
		g[y].push_back(Node{x,1});
	}
//	for(int i=1;i<=n;i++)
//	{
//		for(int j=1;j<=n;j++)
//		{
//			if(a[i][j]!=inf) g[i].push_back(Node{j,a[i][j]});
//		}
//	}
	dij();
	for(int i=1;i<=n;i++)
	{
		cout<<ans[i]<<"\n";
	}
	return 0;
}
